import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { searchRentals, fetchStates, fetchPropertyTypes } from '../utils/api';
import { LoadingState, ErrorState, EmptyState } from '../components/LoadingState';
import Pagination from '../components/Pagination';

const SORT_COLUMNS = [
  { value: 'rent', label: 'Price' },
  { value: 'bedrooms', label: 'Bedrooms' },
  { value: 'bathrooms', label: 'Bathrooms' },
  { value: 'parkingSpaces', label: 'Parking' },
  { value: 'suburb', label: 'Suburb' },
];

const formatPrice = (p) => (p != null ? `$${Number(p).toLocaleString('en-AU')}/wk` : '—');

const SearchPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [states, setStates] = useState([]);
  const [propertyTypes, setPropertyTypes] = useState([]);

  // Filter keys match API camelCase param names exactly
  const [filters, setFilters] = useState({
    state: searchParams.get('state') || '',
    suburb: searchParams.get('suburb') || '',
    postcode: searchParams.get('postcode') || '',
    propertyType: searchParams.get('propertyType') || '',
    minPrice: searchParams.get('minPrice') || '',
    maxPrice: searchParams.get('maxPrice') || '',
    bedrooms: searchParams.get('bedrooms') || '',
    bathrooms: searchParams.get('bathrooms') || '',
    parkingSpaces: searchParams.get('parkingSpaces') || '',
    sort_col: searchParams.get('sort_col') || '',
    sort_order: searchParams.get('sort_order') || 'asc',
  });

  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(Number(searchParams.get('page')) || 1);
  const [showAdvanced, setShowAdvanced] = useState(false);

  const debounceRef = useRef(null);

  // Load filter options
  useEffect(() => {
    fetchStates().then(setStates).catch(() => {});
    fetchPropertyTypes().then(setPropertyTypes).catch(() => {});
  }, []);

  const doSearch = useCallback(async (currentFilters, currentPage) => {
    setLoading(true);
    setError(null);
    try {
      const params = { ...currentFilters, page: currentPage };
      // Remove empty values
      Object.keys(params).forEach((k) => {
        if (params[k] === '' || params[k] == null) delete params[k];
      });
      const data = await searchRentals(params);
      setResults(data);
    } catch (err) {
      setError(err.message || 'Search failed. Please try again.');
    } finally {
      setLoading(false);
    }
  }, []);

  // Run search on mount and whenever filters/page change
  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      doSearch(filters, page);
      // Sync URL
      const params = {};
      Object.entries(filters).forEach(([k, v]) => { if (v) params[k] = v; });
      if (page > 1) params.page = page;
      setSearchParams(params, { replace: true });
    }, 400);
    return () => clearTimeout(debounceRef.current);
  }, [filters, page, doSearch, setSearchParams]);

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
    setPage(1);
  };

  const handleSortCol = (col) => {
    setFilters((prev) => ({
      ...prev,
      sort_col: col,
      sort_order: prev.sort_col === col && prev.sort_order === 'asc' ? 'desc' : 'asc',
    }));
    setPage(1);
  };

  const resetFilters = () => {
    setFilters({
      state: '', suburb: '', postcode: '', propertyType: '',
      minPrice: '', maxPrice: '', bedrooms: '', bathrooms: '',
      parkingSpaces: '', sort_col: '', sort_order: 'asc',
    });
    setPage(1);
  };

  const rentals = results?.data || results?.rentals || [];
  const totalPages = results?.pagination?.lastPage || 1;

  return (
    <div className="search-page">
      <div className="search-page__sidebar">
        <div className="filter-panel">
          <div className="filter-panel__header">
            <h2>Filters</h2>
            <button className="btn btn--link" onClick={resetFilters}>Reset</button>
          </div>

          {/* Basic filters */}
          <div className="filter-group">
            <label className="filter-label" htmlFor="filter-state">State</label>
            <select
              id="filter-state"
              className="filter-select"
              value={filters.state}
              onChange={(e) => handleFilterChange('state', e.target.value)}
            >
              <option value="">All States</option>
              {states.map((s) => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          <div className="filter-group">
            <label className="filter-label" htmlFor="filter-type">Property Type</label>
            <select
              id="filter-type"
              className="filter-select"
              value={filters.propertyType}
              onChange={(e) => handleFilterChange('propertyType', e.target.value)}
            >
              <option value="">All Types</option>
              {propertyTypes.map((t) => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>

          <div className="filter-group">
            <label className="filter-label" htmlFor="filter-suburb">Suburb</label>
            <input
              id="filter-suburb"
              className="filter-input"
              type="text"
              placeholder="e.g. Surry Hills"
              value={filters.suburb}
              onChange={(e) => handleFilterChange('suburb', e.target.value)}
            />
          </div>

          <div className="filter-group">
            <label className="filter-label" htmlFor="filter-postcode">Postcode</label>
            <input
              id="filter-postcode"
              className="filter-input"
              type="text"
              placeholder="e.g. 2010"
              value={filters.postcode}
              onChange={(e) => handleFilterChange('postcode', e.target.value)}
            />
          </div>

          {/* Advanced toggle */}
          <button
            className="btn btn--link filter-advanced-toggle"
            onClick={() => setShowAdvanced(!showAdvanced)}
          >
            {showAdvanced ? '− Hide Advanced' : '+ Advanced Filters'}
          </button>

          {showAdvanced && (
            <>
              <div className="filter-row">
                <div className="filter-group filter-group--half">
                  <label className="filter-label">Min Price/wk</label>
                  <input
                    className="filter-input"
                    type="number"
                    min="0"
                    placeholder="$0"
                    value={filters.minPrice}
                    onChange={(e) => handleFilterChange('minPrice', e.target.value)}
                  />
                </div>
                <div className="filter-group filter-group--half">
                  <label className="filter-label">Max Price/wk</label>
                  <input
                    className="filter-input"
                    type="number"
                    min="0"
                    placeholder="Any"
                    value={filters.maxPrice}
                    onChange={(e) => handleFilterChange('maxPrice', e.target.value)}
                  />
                </div>
              </div>

              <div className="filter-row">
                <div className="filter-group filter-group--half">
                  <label className="filter-label">Bedrooms</label>
                  <input
                    className="filter-input"
                    type="number"
                    min="0"
                    placeholder="Any"
                    value={filters.bedrooms}
                    onChange={(e) => handleFilterChange('bedrooms', e.target.value)}
                  />
                </div>
                <div className="filter-group filter-group--half">
                  <label className="filter-label">Bathrooms</label>
                  <input
                    className="filter-input"
                    type="number"
                    min="0"
                    placeholder="Any"
                    value={filters.bathrooms}
                    onChange={(e) => handleFilterChange('bathrooms', e.target.value)}
                  />
                </div>
              </div>

              <div className="filter-group">
                <label className="filter-label">Parking Spaces</label>
                <input
                  className="filter-input"
                  type="number"
                  min="0"
                  placeholder="Any"
                  value={filters.parkingSpaces}
                  onChange={(e) => handleFilterChange('parkingSpaces', e.target.value)}
                />
              </div>
            </>
          )}

          {/* Sort */}
          <div className="filter-group">
            <label className="filter-label">Sort By</label>
            <select
              className="filter-select"
              value={filters.sort_col}
              onChange={(e) => handleFilterChange('sort_col', e.target.value)}
            >
              <option value="">Default</option>
              {SORT_COLUMNS.map((c) => (
                <option key={c.value} value={c.value}>{c.label}</option>
              ))}
            </select>
          </div>

          {filters.sort_col && (
            <div className="filter-group">
              <label className="filter-label">Sort Order</label>
              <div className="filter-toggle">
                <button
                  className={`filter-toggle__btn${filters.sort_order === 'asc' ? ' filter-toggle__btn--active' : ''}`}
                  onClick={() => handleFilterChange('sort_order', 'asc')}
                >↑ Asc</button>
                <button
                  className={`filter-toggle__btn${filters.sort_order === 'desc' ? ' filter-toggle__btn--active' : ''}`}
                  onClick={() => handleFilterChange('sort_order', 'desc')}
                >↓ Desc</button>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Results */}
      <div className="search-page__results">
        <div className="results-header">
          <h1 className="results-header__title">
            {loading ? 'Searching…' : results ? `${Array.isArray(rentals) ? rentals.length : 0} results` : 'Rental Properties'}
          </h1>
          <div className="results-header__sort">
            {SORT_COLUMNS.map((c) => (
              <button
                key={c.value}
                className={`sort-btn${filters.sort_col === c.value ? ' sort-btn--active' : ''}`}
                onClick={() => handleSortCol(c.value)}
              >
                {c.label}
                {filters.sort_col === c.value && (
                  <span>{filters.sort_order === 'asc' ? ' ↑' : ' ↓'}</span>
                )}
              </button>
            ))}
          </div>
        </div>

        {loading && <LoadingState message="Searching properties…" />}

        {!loading && error && (
          <ErrorState message={error} onRetry={() => doSearch(filters, page)} />
        )}

        {!loading && !error && Array.isArray(rentals) && rentals.length === 0 && (
          <EmptyState
            icon="🏘️"
            title="No properties found"
            subtitle="Try adjusting your filters to see more results."
          />
        )}

        {!loading && !error && Array.isArray(rentals) && rentals.length > 0 && (
          <>
            <div className="results-table-wrapper">
              <table className="results-table" role="grid">
                <thead>
                  <tr>
                    <th>Address</th>
                    <th>Suburb</th>
                    <th>State</th>
                    <th>Type</th>
                    <th>Bed</th>
                    <th>Bath</th>
                    <th>Park</th>
                    <th>Price/wk</th>
                  </tr>
                </thead>
                <tbody>
                  {rentals.map((r) => (
                    <tr
                      key={r.id}
                      className="results-table__row"
                      onClick={() => navigate(`/rental/${r.id}`)}
                      role="button"
                      tabIndex={0}
                      onKeyDown={(e) => e.key === 'Enter' && navigate(`/rental/${r.id}`)}
                      aria-label={`View ${r.title || r.suburb}`}
                    >
                      <td className="results-table__address">{r.title || r.suburb || '—'}</td>
                      <td>{r.suburb || '—'}</td>
                      <td><span className="badge">{r.state}</span></td>
                      <td>{r.propertyType || '—'}</td>
                      <td>{r.bedrooms ?? '—'}</td>
                      <td>{r.bathrooms ?? '—'}</td>
                      <td>{r.parkingSpaces ?? '—'}</td>
                      <td className="results-table__price">{formatPrice(r.rent)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <Pagination
              page={page}
              totalPages={totalPages}
              onPageChange={(p) => {
                setPage(p);
                window.scrollTo({ top: 0, behavior: 'smooth' });
              }}
            />
          </>
        )}
      </div>
    </div>
  );
};

export default SearchPage;
